SELECT  FROM hub_job
WHERE request_id = #{requestId}
  AND payload ->> 'corpId' = CAST(#{corpId} AS varchar)

SELECT  FROM hub_job

    AND payload ->> 'corpId' = CAST(#{corpId} AS varchar)
    AND status = #{status}
    AND channel_cd = #{channelCd}

ORDER BY updated_at DESC, created_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM hub_job

    AND payload ->> 'corpId' = CAST(#{corpId} AS varchar)
    AND status = #{status}
    AND channel_cd = #{channelCd}
